      buttonPrimary: 'cyber-btn-primary',
      buttonSecondary: 'cyber-btn-secondary',
      input: 'cyber-input',
      badge: 'cyber-badge'
    },
    injectCss: `
      /* --- CYBERPUNK V4: ARASAKA PROTOCOL --- */

      /* 1. CRT MONITOR DISTORTION */
      .ds-page-root {
        animation: crt-flicker 0.1s infinite;
      }

      @keyframes crt-flicker {
        0% { opacity: 0.99; }
        100% { opacity: 1; }
      }

      .ds-page-root::before {
        content: " ";
        display: block;
        position: fixed;
        top: 0; left: 0; bottom: 0; right: 0;
        background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.25) 50%), linear-gradient(90deg, rgba(255, 0, 0, 0.06), rgba(0, 255, 0, 0.02), rgba(0, 0, 255, 0.06));
        z-index: 999;
        background-size: 100% 2px, 3px 100%;
        pointer-events: none;
      }

      /* 2. GLITCH BUTTONS */
      .cyber-btn-primary {
        --clip: polygon(0 0, 100% 0, 100% 100%, 0 100%);
        position: relative;
        background: var(--text-primary);
        color: #000;
        font-weight: 900;
        text-transform: uppercase;
        border: 0;
        letter-spacing: 2px;
        clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px);
        transition: all 0.2s cubic-bezier(0.25, 1, 0.5, 1);
      }

      .cyber-btn-primary:hover {
        transform: translate(-2px, -2px);
        box-shadow: 4px 4px 0 var(--text-secondary);
        background: #fff;
        text-shadow: -1px -1px 0 rgba(0,240,255,0.5), 1px 1px 0 rgba(255,0,60,0.5);
      }

      .cyber-btn-primary::after {
        content: '';
        position: absolute;
        top: 0; left: 0; right: 0; bottom: 0;
        background: var(--accent-color);
        mix-blend-mode: hard-light;
        opacity: 0;
        z-index: 1;
      }
      .cyber-btn-primary:active::after {
        opacity: 0.5;
      }

      /* 3. HERO TYPOGRAPHY (DECODING EFFECT) */
      .ds-hero-title {
        text-shadow: 2px 0 0 rgba(255,0,60,0.8), -2px 0 0 rgba(0,240,255,0.8);
        animation: text-glitch 3s infinite alternate;
      }
      @keyframes text-glitch {
        0% { text-shadow: 2px 0 0 rgba(255,0,60,0.8), -2px 0 0 rgba(0,240,255,0.8); }
        98% { text-shadow: 2px 0 0 rgba(255,0,60,0.8), -2px 0 0 rgba(0,240,255,0.8); }
        99% { text-shadow: -2px 0 0 rgba(255,0,60,0.8), 2px 0 0 rgba(0,240,255,0.8); transform: skewX(10deg); }
        100% { text-shadow: 2px 0 0 rgba(255,0,60,0.8), -2px 0 0 rgba(0,240,255,0.8); transform: skewX(0deg); }
      }

      .ds-hero-title span {
        background: var(--text-primary);
        color: #000;
        padding: 0 10px;
      }

      /* 4. DATA PANELS */
      .cyber-panel, .ds-panel, .ds-card {
        background: #080808;
        border: 1px solid #333;
        position: relative;
        box-shadow: 0 0 20px rgba(0,0,0,0.5);
      }
      /* Corner brackets */
      .cyber-panel::before, .ds-panel::before, .ds-card::before {
        content: "";
        position: absolute;
        top: -1px; left: -1px; width: 20px; height: 20px;
        border-top: 2px solid var(--text-primary);
        border-left: 2px solid var(--text-primary);
      }
      .cyber-panel::after, .ds-panel::after, .ds-card::after {
        content: "";
        position: absolute;
        bottom: -1px; right: -1px; width: 20px; height: 20px;
        border-bottom: 2px solid var(--text-primary);
        border-right: 2px solid var(--text-primary);
      }

      .cyber-panel:hover, .ds-panel:hover, .ds-card:hover {
        border-color: var(--text-secondary);
        box-shadow: 0 0 15px rgba(0, 240, 255, 0.1);
      }

      /* 5. INPUT TERMINAL */
      .cyber-input {
        background: #050505;
        border: 1px solid #333;
        border-left: 4px solid var(--text-primary);
        font-family: var(--font-display);
        color: var(--text-primary);
        transition: all 0.3s;
      }
      .cyber-input:focus {
        background: #000;
        border-color: var(--text-secondary);
        box-shadow: 0 0 20px rgba(0, 240, 255, 0.2);
        outline: none;
      }

      /* 6. STATS & TABLES */
      .ds-table-container {
        border: 1px solid #222;
        background: repeating-linear-gradient(0deg, #0a0a0a, #0a0a0a 2px, #0f0f0f 2px, #0f0f0f 4px);
      }
      .ds-table-container > div:first-child {
        background: var(--accent-color);
        color: #000;
        font-weight: 900;
      }
      .ds-table-container > div:not(:first-child):hover {
        background: var(--text-secondary) !important;
        color: #000 !important;
        cursor: crosshair;
      }
      /* Force children to black on hover */
      .ds-table-container > div:not(:first-child):hover * {
        color: #000 !important;
      }

      /* 7. SCROLLBAR */
      ::-webkit-scrollbar {
        width: 8px;
        background: #000;
      }
      ::-webkit-scrollbar-thumb {
        background: #333;
        border: 1px solid #000;
      }
      ::-webkit-scrollbar-thumb:hover {
        background: var(--text-primary);
      }

      /* 8. INTERACTIVE TOGGLES (Cyber Switch) */
      .mannequin-toggle-track {
        background: #1a1a1a;
        border: 1px solid #333;
        border-radius: 0;
      }
      .mannequin-toggle-track.active {
        background: var(--text-primary); /* Yellow */
        box-shadow: 0 0 10px var(--text-primary);
        border-color: var(--text-primary);
      }
      .mannequin-toggle-thumb {
        background: #000;
        border-radius: 0;
        border: 1px solid #333;
      }

      /* 9. TABS (Glitch Tabs) */
      .ds-nav-links span {
         position: relative;
         text-transform: uppercase;
      }
      .ds-nav-links span:hover {
         color: var(--accent-color); /* Red */
         text-shadow: 2px 0 var(--text-secondary);
      }

      /* 10. SELECTED CARD */
      .ds-card.selected {
         border: 1px solid var(--accent-color);
         box-shadow: 0 0 30px rgba(255, 0, 60, 0.2);
         animation: border-pulse 2s infinite;
      }
      @keyframes border-pulse {
         0% { border-color: var(--accent-color); }
         50% { border-color: var(--text-secondary); }
         100% { border-color: var(--accent-color); }
      }
    `
  }
};

