      .ds-table-container > div:not(:first-child):hover * {
         color: #000 !important;
      }
      /* Status */
      .ds-table-container span {
        background: transparent !important;
        border: 1px solid currentColor;
        border-radius: 0;
        padding: 2px 5px;
