        color: #E0B0FF;
      }

      /* Pricing */
      .ds-card:nth-child(2) {
        border: 1px solid #E0B0FF !important;
        background: rgba(255,255,255,0.7) !important;
        box-shadow: 0 20px 50px rgba(224, 176, 255, 0.3) !important;
      }
      .ds-card:nth-child(2) .ds-card-title {
        color: #E0B0FF;
