      .ds-card:nth-child(2) .absolute {
        background: #E0B0FF;
        color: #FFF;
        border-radius: 0 0 20px 20px;
        padding: 8px 24px;
        font-family: 'Cormorant Garamond', serif;
      }

      /* 10. TOGGLES (Glowing Orb) */
      .mannequin-toggle-track {
        background: rgba(255, 255, 255, 0.5);
